/**
 * WebSocket client for the fs9 filesystem protocol.
 *
 * Mirrors db9-cli/src/fssh/client.rs — each public method maps to a single
 * request–response round-trip over a JSON text WebSocket.
 *
 * For files >= 1 MB, writeFile() automatically switches to streaming mode
 * using binary WebSocket frames to bypass the 2 MB JSON frame limit and
 * eliminate base64 encoding overhead.
 *
 * Node-only: requires the `ws` package or Node 21+ native WebSocket.
 */

import { createHash } from 'node:crypto';
import type {
  FileInfo,
  FsAuthInfo,
  FsWsResponse,
  FsWsError,
  StreamWriteReady,
} from './fs-types';

// ── Types ───────────────────────────────────────────────────────

/** Minimal WebSocket interface we depend on (compatible with `ws` package). */
export interface WebSocketLike {
  readonly readyState: number;
  send(data: string | Buffer | Uint8Array): void;
  close(code?: number, reason?: string): void;
  onopen: ((ev: unknown) => void) | null;
  onclose: ((ev: unknown) => void) | null;
  onerror: ((ev: unknown) => void) | null;
  onmessage: ((ev: { data: unknown }) => void) | null;
}

/** Constructor for a W3C-compatible WebSocket. */
export type WebSocketConstructor = new (url: string) => WebSocketLike;

/** Error from an fs9 WebSocket operation. */
export class FsError extends Error {
  readonly code: string;

  constructor(code: string, message: string) {
    super(message);
    this.name = 'FsError';
    this.code = code;
  }
}

// ── Constants ────────────────────────────────────────────────────

/** Threshold above which streaming mode is used (matches server/Rust client). */
const STREAMING_THRESHOLD = 1024 * 1024; // 1 MB

/** Default chunk size for streaming transfers. */
const DEFAULT_CHUNK_SIZE = 64 * 1024; // 64 KB

// ── Request ID ──────────────────────────────────────────────────

let nextId = 1;
function nextRequestId(): string {
  return String(nextId++);
}

// ── Helpers ──────────────────────────────────────────────────────

function toBase64(data: Uint8Array | ArrayBuffer): string {
  const bytes = data instanceof Uint8Array ? data : new Uint8Array(data);
  return Buffer.from(bytes).toString('base64');
}

function fromBase64(b64: string): Uint8Array {
  return new Uint8Array(Buffer.from(b64, 'base64'));
}

/** Compute SHA-256 checksum, returning "sha256:<hex>". */
function computeChecksum(data: Uint8Array): string {
  const hash = createHash('sha256').update(data).digest('hex');
  return `sha256:${hash}`;
}

/** Encode a binary frame: [8-byte stream_id BE][chunk_data]. */
function encodeBinaryFrame(streamId: number, chunk: Uint8Array): Buffer {
  const frame = Buffer.alloc(8 + chunk.length);
  frame.writeBigUInt64BE(BigInt(streamId), 0);
  frame.set(chunk, 8);
  return frame;
}

// ── FsClient ────────────────────────────────────────────────────

/**
 * Async WebSocket client for fs9 file operations.
 *
 * Usage:
 * ```ts
 * const client = await FsClient.connect('wss://host:5480', WebSocket);
 * await client.authenticate('tenant.admin', 'password');
 * const entries = await client.readdir('/');
 * await client.close();
 * ```
 */
export class FsClient {
  private ws: WebSocketLike;
  private pending = new Map<string, {
    resolve: (resp: FsWsResponse) => void;
    reject: (err: Error) => void;
  }>();
  private closed = false;

  private constructor(ws: WebSocketLike) {
    this.ws = ws;
    ws.onmessage = (ev: { data: unknown }) => {
      const text = typeof ev.data === 'string' ? ev.data : String(ev.data);
      let resp: FsWsResponse;
      try {
        resp = JSON.parse(text) as FsWsResponse;
      } catch {
        return; // ignore non-JSON frames
      }
      const p = this.pending.get(resp.id);
      if (p) {
        this.pending.delete(resp.id);
        p.resolve(resp);
      }
    };
    ws.onclose = () => {
      this.closed = true;
      // Reject all pending requests
      for (const [, p] of this.pending) {
        p.reject(new FsError('CONNECTION_CLOSED', 'WebSocket connection closed'));
      }
      this.pending.clear();
    };
    ws.onerror = () => {
      // onclose will fire after onerror, which handles cleanup
    };
  }

  /**
   * Connect to an fs9 WebSocket server.
   *
   * @param url WebSocket URL, e.g. `wss://host:5480`
   * @param WS  WebSocket constructor (native or from `ws` package)
   */
  static connect(url: string, WS: WebSocketConstructor): Promise<FsClient> {
    return new Promise((resolve, reject) => {
      const ws = new WS(url);
      ws.onopen = () => {
        ws.onopen = null;
        ws.onerror = null;
        resolve(new FsClient(ws));
      };
      ws.onerror = (ev: unknown) => {
        ws.onopen = null;
        ws.onerror = null;
        const msg = ev && typeof ev === 'object' && 'message' in ev
          ? String((ev as { message: unknown }).message)
          : 'WebSocket connection failed';
        reject(new FsError('CONNECTION_ERROR', msg));
      };
    });
  }

  /** Authenticate with the server. Must be called first after connect. */
  async authenticate(username: string, password: string): Promise<FsAuthInfo> {
    const resp = await this.sendAndRecv({
      id: nextRequestId(),
      op: 'auth',
      username,
      password,
    });
    if (!resp.ok) {
      throw new FsError('AUTH_FAILED', this.errorMessage(resp));
    }
    const data = resp.data as Record<string, unknown> | undefined;
    return {
      user: String(data?.user ?? ''),
      tenant: String(data?.tenant ?? ''),
      keyspace: String(data?.keyspace ?? ''),
    };
  }

  /** Get file or directory metadata. */
  async stat(path: string): Promise<FileInfo> {
    const resp = await this.sendAndRecv({
      id: nextRequestId(),
      op: 'stat',
      path,
    });
    this.expectOk(resp);
    return resp.data as FileInfo;
  }

  /** List directory contents. */
  async readdir(path: string): Promise<FileInfo[]> {
    const resp = await this.sendAndRecv({
      id: nextRequestId(),
      op: 'readdir',
      path,
    });
    this.expectOk(resp);
    const data = resp.data as { entries: FileInfo[] } | undefined;
    return data?.entries ?? [];
  }

  /** Create a directory. Always recursive (mkdir -p). */
  async mkdir(path: string, recursive = true): Promise<void> {
    const resp = await this.sendAndRecv({
      id: nextRequestId(),
      op: 'mkdir',
      path,
      recursive,
    });
    this.expectOk(resp);
  }

  /** Read an entire file, returning raw bytes. */
  async readFile(path: string): Promise<Uint8Array> {
    const resp = await this.sendAndRecv({
      id: nextRequestId(),
      op: 'read',
      path,
    });
    this.expectOk(resp);
    const data = resp.data as { content?: string } | undefined;
    const content = data?.content;
    if (typeof content !== 'string') {
      throw new FsError('PROTOCOL', 'missing content field in read response');
    }
    return fromBase64(content);
  }

  /**
   * Write (overwrite) a file. Returns bytes written.
   *
   * Automatically uses streaming mode for files >= 1 MB to avoid base64
   * overhead and bypass the 2 MB JSON frame limit.
   */
  async writeFile(path: string, data: Uint8Array | ArrayBuffer | string): Promise<number> {
    const bytes = typeof data === 'string'
      ? new TextEncoder().encode(data)
      : data instanceof Uint8Array ? data : new Uint8Array(data);
    if (bytes.byteLength >= STREAMING_THRESHOLD) {
      return this.writeFileStreaming(path, bytes);
    }
    const resp = await this.sendAndRecv({
      id: nextRequestId(),
      op: 'write',
      path,
      content: toBase64(bytes),
      encoding: 'base64',
    });
    this.expectOk(resp);
    const result = resp.data as { written?: number } | undefined;
    return result?.written ?? bytes.byteLength;
  }

  /** Append to a file. Returns bytes written. */
  async appendFile(path: string, data: Uint8Array | ArrayBuffer | string): Promise<number> {
    const bytes = typeof data === 'string'
      ? new TextEncoder().encode(data)
      : data instanceof Uint8Array ? data : new Uint8Array(data);
    const resp = await this.sendAndRecv({
      id: nextRequestId(),
      op: 'append',
      path,
      content: toBase64(bytes),
      encoding: 'base64',
    });
    this.expectOk(resp);
    const result = resp.data as { written?: number } | undefined;
    return result?.written ?? bytes.byteLength;
  }

  /** Remove a file (non-recursive) or directory (recursive). */
  async rm(path: string, recursive = false): Promise<void> {
    const resp = await this.sendAndRecv(recursive
      ? { id: nextRequestId(), op: 'rm', path, recursive: true }
      : { id: nextRequestId(), op: 'unlink', path }
    );
    this.expectOk(resp);
  }

  /** Rename (move) a file or directory. */
  async rename(oldPath: string, newPath: string): Promise<void> {
    const resp = await this.sendAndRecv({
      id: nextRequestId(),
      op: 'rename',
      old_path: oldPath,
      new_path: newPath,
    });
    this.expectOk(resp);
  }

  /** Gracefully close the WebSocket connection. */
  async close(): Promise<void> {
    if (!this.closed) {
      this.ws.close();
    }
  }

  // ── streaming internals ────────────────────────────────────────

  /**
   * Write a file using streaming mode (binary frames, no base64).
   *
   * Protocol:
   * 1. Send streaming write request with file size
   * 2. Receive ready response with stream_id and chunk_size
   * 3. Send binary frames: [8-byte stream_id BE][chunk_data]
   * 4. Send stream end with checksum
   * 5. Receive final write confirmation
   */
  private async writeFileStreaming(path: string, bytes: Uint8Array): Promise<number> {
    // 1. Initiate streaming write
    const requestId = nextRequestId();
    const readyResp = await this.sendAndRecv({
      id: requestId,
      op: 'write',
      path,
      streaming: true,
      size: bytes.byteLength,
    });
    this.expectOk(readyResp);

    const ready = readyResp.data as StreamWriteReady | undefined;
    if (!ready?.ready) {
      throw new FsError('PROTOCOL', 'server not ready for streaming');
    }

    const streamId = ready.stream_id;
    const chunkSize = ready.chunk_size > 0 ? ready.chunk_size : DEFAULT_CHUNK_SIZE;

    // 3. Send binary frames (abort stream on failure)
    try {
      for (let offset = 0; offset < bytes.byteLength; offset += chunkSize) {
        const chunk = bytes.subarray(offset, offset + chunkSize);
        const frame = encodeBinaryFrame(streamId, chunk);
        this.ws.send(frame);
      }
    } catch (err) {
      this.tryAbortStream(streamId);
      throw new FsError('CONNECTION_ERROR', `send chunk: ${err}`);
    }

    // 4. Send stream end with checksum
    const checksum = computeChecksum(bytes);
    const finalResp = await this.sendAndRecv({
      id: requestId,
      stream: 'end',
      stream_id: streamId,
      checksum,
    });
    this.expectOk(finalResp);

    const result = finalResp.data as { written?: number } | undefined;
    return result?.written ?? bytes.byteLength;
  }

  /** Best-effort abort of an in-progress stream so the server can clean up. */
  private tryAbortStream(streamId: number): void {
    try {
      this.ws.send(JSON.stringify({ stream: 'abort', stream_id: streamId }));
    } catch {
      // best-effort — ignore send failures during abort
    }
  }

  // ── internals ──────────────────────────────────────────────────

  private sendAndRecv(request: Record<string, unknown>): Promise<FsWsResponse> {
    if (this.closed) {
      return Promise.reject(new FsError('CONNECTION_CLOSED', 'WebSocket is closed'));
    }
    return new Promise((resolve, reject) => {
      const id = request.id as string;
      this.pending.set(id, { resolve, reject });
      try {
        this.ws.send(JSON.stringify(request));
      } catch (err) {
        this.pending.delete(id);
        reject(new FsError('CONNECTION_ERROR', String(err)));
      }
    });
  }

  private expectOk(resp: FsWsResponse): void {
    if (!resp.ok) {
      const detail = resp.error as FsWsError | undefined;
      throw new FsError(
        detail?.code ?? 'UNKNOWN',
        detail?.message ?? 'unknown error',
      );
    }
  }

  private errorMessage(resp: FsWsResponse): string {
    const detail = resp.error as FsWsError | undefined;
    return detail ? `${detail.code}: ${detail.message}` : 'unknown error';
  }
}
