import { createHttpClient, type FetchFn, type HttpClient } from './http';
import {
  defaultCredentialStore,
  type CredentialStore,
} from './credentials';
import { Db9Error } from './errors';
import type { FileInfo, FsConnectOptions } from './fs-types';
import { FsClient, FsError, type WebSocketConstructor } from './ws';
import type {
  CustomerResponse,
  TokenResponse,
  MessageResponse,
  CreateDatabaseRequest,
  DatabaseResponse,
  CustomerPasswordResetResponse,
  TenantObservabilityResponse,
  SqlResult,
  SqlErrorDetail,
  SchemaResponse,
  DumpRequest,
  DumpResponse,
  MigrationApplyRequest,
  MigrationApplyResponse,
  MigrationMetadata,
  BranchRequest,
  UserResponse,
  CreateUserRequest,
  CreateTokenRequest,
  CreateTokenResponse,
} from './types';

export interface Db9ClientOptions {
  baseUrl?: string;
  token?: string;
  fetch?: FetchFn;
  credentialStore?: CredentialStore;
  timeout?: number;
  maxRetries?: number;
  retryDelay?: number;
  /** WebSocket constructor for fs operations (native WebSocket, or `ws` package for Node 18–20). */
  WebSocket?: WebSocketConstructor;
  /** WebSocket port for fs9 server (default: 5480). */
  wsPort?: number;
}

export function createDb9Client(options: Db9ClientOptions = {}) {
  const baseUrl =
    options.baseUrl ?? 'https://db9.ai/api';
  let token = options.token;
  let tokenLoaded = !!token;
  const store = options.credentialStore ?? defaultCredentialStore();
  const fetchFn = options.fetch ?? globalThis.fetch;

  // Public HTTP client — no Authorization header
  const publicClient = createHttpClient({
    baseUrl,
    fetch: options.fetch,
    timeout: options.timeout,
    maxRetries: options.maxRetries,
    retryDelay: options.retryDelay,
  });

  // Lazy-loading authenticated HTTP client
  async function getAuthClient(): Promise<HttpClient> {
    if (!token && !tokenLoaded) {
      const creds = await store.load();
      if (creds?.token) token = creds.token;
      tokenLoaded = true;
    }
    if (!token) {
      throw new Db9Error(
        'No token available. Run `db9 login` or pass a token via Db9ClientOptions.',
        401
      );
    }
    return createHttpClient({
      baseUrl,
      fetch: options.fetch,
      headers: { Authorization: `Bearer ${token}` },
      timeout: options.timeout,
      maxRetries: options.maxRetries,
      retryDelay: options.retryDelay,
    });
  }

  async function withAuthRetry<T>(
    operation: (client: HttpClient) => Promise<T>
  ): Promise<T> {
    const client = await getAuthClient();
    return operation(client);
  }

  // ── fs9 WebSocket helpers ───────────────────────────────────
  const fsWsPort = options.wsPort ?? 5480;

  /**
   * Resolve WebSocket connection credentials for a database.
   * Uses the credentials API to get host, username, and password,
   * then constructs the WS URL and auth username.
   */
  async function resolveFsConn(dbId: string): Promise<FsConnectOptions> {
    // Try credentials endpoint first (returns admin_user, admin_password, connection_string)
    const creds = await withAuthRetry((client) =>
      client.get<CustomerPasswordResetResponse>(
        `/customer/databases/${dbId}/credentials`
      )
    );

    // Parse host from connection_string: postgresql://tenant.user:pass@HOST:port/db
    const connStr = creds.connection_string;
    const hostMatch = connStr.match(/@([^:/?]+)/);
    const host = hostMatch?.[1];
    if (!host) {
      throw new Error(`Cannot parse host from connection string for database '${dbId}'`);
    }

    // Username format: connection_string already has tenant.user, extract it
    const userMatch = connStr.match(/:\/\/([^:@]+)/);
    const username = userMatch?.[1] ?? creds.admin_user;

    const protocol = host === 'localhost' || host === '127.0.0.1' ? 'ws' : 'wss';

    return {
      wsUrl: `${protocol}://${host}:${fsWsPort}`,
      username,
      password: creds.admin_password,
    };
  }

  /**
   * Run an operation on an authenticated FsClient, then close the connection.
   * The WebSocket constructor must be provided via `Db9ClientOptions.WebSocket`.
   */
  async function withFsClient<T>(
    dbId: string,
    operation: (client: FsClient) => Promise<T>
  ): Promise<T> {
    const WS = options.WebSocket ?? (typeof globalThis !== 'undefined' ? (globalThis as Record<string, unknown>).WebSocket as WebSocketConstructor | undefined : undefined);
    if (!WS) {
      throw new Error(
        'WebSocket constructor not available. Pass `WebSocket` in Db9ClientOptions, ' +
        'or use Node 21+ / a browser environment with native WebSocket support, ' +
        'or install the `ws` package for Node 18–20.'
      );
    }

    const conn = await resolveFsConn(dbId);
    const client = await FsClient.connect(conn.wsUrl, WS);
    try {
      await client.authenticate(conn.username, conn.password);
      return await operation(client);
    } finally {
      await client.close();
    }
  }

  // ── SQL Error Parsing ────────────────────────────────────────
  function parseSqlError(raw: string): SqlErrorDetail {
    // Strategy 1: Try JSON.parse
    try {
      const parsed = JSON.parse(raw);
      if (typeof parsed === 'object' && parsed !== null && typeof parsed.message === 'string') {
        return parsed as SqlErrorDetail;
      }
    } catch {
      // not JSON, continue
    }

    // Strategy 2: Regex for PostgreSQL-style errors
    const pgMatch = raw.match(/^(?:ERROR:\s*)?(.+?)(?:\s+DETAIL:\s+(.+?))?(?:\s+HINT:\s+(.+?))?(?:\s+\(SQLSTATE\s+(\w+)\))?$/s);
    if (pgMatch && pgMatch[1]) {
      const result: SqlErrorDetail = { message: pgMatch[1].trim() };
      if (pgMatch[2]) result.detail = pgMatch[2].trim();
      if (pgMatch[3]) result.hint = pgMatch[3].trim();
      if (pgMatch[4]) result.code = pgMatch[4];
      return result;
    }

    // Strategy 3: Fallback
    return { message: raw };
  }

  return {
    auth: {
      me: async () =>
        withAuthRetry((client) =>
          client.get<CustomerResponse>('/customer/me')
        ),
    },

    tokens: {
      list: async () =>
        withAuthRetry((client) =>
          client.get<TokenResponse[]>('/customer/tokens')
        ),

      revoke: async (tokenId: string) =>
        withAuthRetry((client) =>
          client.del<MessageResponse>(`/customer/tokens/${tokenId}`)
        ),

      create: async (req: CreateTokenRequest) =>
        withAuthRetry((client) =>
          client.post<CreateTokenResponse>('/customer/tokens', req)
        ),
    },

    databases: {
      // ── CRUD ──────────────────────────────────────────────────
      create: async (req: CreateDatabaseRequest) =>
        withAuthRetry((client) =>
          client.post<DatabaseResponse>('/customer/databases', req)
        ),

      list: async () =>
        withAuthRetry((client) =>
          client.get<DatabaseResponse[]>('/customer/databases')
        ),

      get: async (databaseId: string) =>
        withAuthRetry((client) =>
          client.get<DatabaseResponse>(
            `/customer/databases/${databaseId}`
          )
        ),

      delete: async (databaseId: string) =>
        withAuthRetry((client) =>
          client.del<MessageResponse>(
            `/customer/databases/${databaseId}`
          )
        ),

      resetPassword: async (databaseId: string) =>
        withAuthRetry((client) =>
          client.post<CustomerPasswordResetResponse>(
            `/customer/databases/${databaseId}/reset-password`
          )
        ),

      credentials: async (databaseId: string) =>
        withAuthRetry((client) =>
          client.get<CustomerPasswordResetResponse>(
            `/customer/databases/${databaseId}/credentials`
          )
        ),


      observability: async (databaseId: string) =>
        withAuthRetry((client) =>
          client.get<TenantObservabilityResponse>(
            `/customer/databases/${databaseId}/observability`
          )
        ),

      // ── SQL Execution ─────────────────────────────────────────
      sql: async (databaseId: string, query: string) => {
        const result = await withAuthRetry((client) =>
          client.post<SqlResult>(
            `/customer/databases/${databaseId}/sql`,
            { query }
          )
        );
        if (result.error && typeof result.error === 'string') {
          result.error = parseSqlError(result.error);
        }
        return result;
      },

      sqlFile: async (databaseId: string, fileContent: string) => {
        const result = await withAuthRetry((client) =>
          client.post<SqlResult>(
            `/customer/databases/${databaseId}/sql`,
            { file_content: fileContent }
          )
        );
        if (result.error && typeof result.error === 'string') {
          result.error = parseSqlError(result.error);
        }
        return result;
      },

      // ── Schema & Dump ─────────────────────────────────────────
      schema: async (databaseId: string) =>
        withAuthRetry((client) =>
          client.get<SchemaResponse>(
            `/customer/databases/${databaseId}/schema`
          )
        ),

      dump: async (databaseId: string, req?: DumpRequest) =>
        withAuthRetry((client) =>
          client.post<DumpResponse>(
            `/customer/databases/${databaseId}/dump`,
            req
          )
        ),

      // ── Migrations ────────────────────────────────────────────
      applyMigration: async (
        databaseId: string,
        req: MigrationApplyRequest
      ) =>
        withAuthRetry((client) =>
          client.post<MigrationApplyResponse>(
            `/customer/databases/${databaseId}/migrations`,
            req
          )
        ),

      listMigrations: async (databaseId: string) =>
        withAuthRetry((client) =>
          client.get<MigrationMetadata[]>(
            `/customer/databases/${databaseId}/migrations`
          )
        ),

      // ── Branching ─────────────────────────────────────────────
      branch: async (databaseId: string, req: BranchRequest) =>
        withAuthRetry((client) =>
          client.post<DatabaseResponse>(
            `/customer/databases/${databaseId}/branch`,
            req
          )
        ),

      // ── User Management ───────────────────────────────────────
      users: {
        list: async (databaseId: string) =>
          withAuthRetry((client) =>
            client.get<UserResponse[]>(
              `/customer/databases/${databaseId}/users`
            )
          ),

        create: async (databaseId: string, req: CreateUserRequest) =>
          withAuthRetry((client) =>
            client.post<MessageResponse>(
              `/customer/databases/${databaseId}/users`,
              req
            )
          ),

        delete: async (databaseId: string, username: string) =>
          withAuthRetry((client) =>
            client.del<MessageResponse>(
              `/customer/databases/${databaseId}/users/${username}`
            )
          ),
      },
    },

    fs: {
      /**
       * Open a persistent WebSocket connection for multiple fs operations.
       * Caller is responsible for calling `client.close()` when done.
       */
      connect: async (dbId: string): Promise<FsClient> => {
        const WS = options.WebSocket ?? (typeof globalThis !== 'undefined' ? (globalThis as Record<string, unknown>).WebSocket as WebSocketConstructor | undefined : undefined);
        if (!WS) {
          throw new Error(
            'WebSocket constructor not available. Pass `WebSocket` in Db9ClientOptions, ' +
            'or use Node 21+ / a browser environment with native WebSocket support, ' +
            'or install the `ws` package for Node 18–20.'
          );
        }
        const conn = await resolveFsConn(dbId);
        const client = await FsClient.connect(conn.wsUrl, WS);
        await client.authenticate(conn.username, conn.password);
        return client;
      },

      /** List directory contents. */
      list: async (dbId: string, path: string): Promise<FileInfo[]> =>
        withFsClient(dbId, (client) => client.readdir(path)),

      /** Read a file as text (UTF-8). */
      read: async (dbId: string, path: string): Promise<string> =>
        withFsClient(dbId, async (client) => {
          const bytes = await client.readFile(path);
          return new TextDecoder().decode(bytes);
        }),

      /** Read a file as raw bytes. */
      readBinary: async (dbId: string, path: string): Promise<Uint8Array> =>
        withFsClient(dbId, (client) => client.readFile(path)),

      /** Write (overwrite) a file. Accepts string, ArrayBuffer, or Uint8Array. */
      write: async (
        dbId: string,
        path: string,
        content: string | ArrayBuffer | Uint8Array
      ): Promise<void> => {
        await withFsClient(dbId, (client) => client.writeFile(path, content));
      },

      /** Append to a file. Returns bytes written. */
      append: async (
        dbId: string,
        path: string,
        content: string | ArrayBuffer | Uint8Array
      ): Promise<number> =>
        withFsClient(dbId, (client) => client.appendFile(path, content)),

      /** Get file or directory metadata. */
      stat: async (dbId: string, path: string): Promise<FileInfo> =>
        withFsClient(dbId, (client) => client.stat(path)),

      /** Check if a file or directory exists. */
      exists: async (dbId: string, path: string): Promise<boolean> => {
        try {
          await withFsClient(dbId, (client) => client.stat(path));
          return true;
        } catch (err) {
          if (err instanceof FsError && err.code === 'ENOENT') {
            return false;
          }
          throw err;
        }
      },

      /** Create a directory (recursive by default). */
      mkdir: async (dbId: string, path: string): Promise<void> => {
        await withFsClient(dbId, (client) => client.mkdir(path, true));
      },

      /** Remove a file or directory. */
      remove: async (dbId: string, path: string, opts?: { recursive?: boolean }): Promise<void> => {
        await withFsClient(dbId, (client) => client.rm(path, opts?.recursive ?? false));
      },

      /** Rename (move) a file or directory. */
      rename: async (dbId: string, oldPath: string, newPath: string): Promise<void> => {
        await withFsClient(dbId, (client) => client.rename(oldPath, newPath));
      },
    },

  };
}

export type Db9Client = ReturnType<typeof createDb9Client>;
